import fs from 'fs'
import path from 'path'

// Tools for keeping examples-site prose linked to the autogenerated JBrowse docs
// (jbrowse.org/jb2/docs/...). Two jobs:
//   - validate that every doc link in the prose still resolves to a real
//     generated page (catches renames/removals like the old WebWorkerRpcDriver)
//   - suggest links: scan an example's config `type: '...'` values and map each
//     to its generated config/model page, so adding "Reference" links is
//     mechanical instead of from-memory
//
// The mapping is exact and deterministic: a config `type` (e.g. `BigWigAdapter`)
// becomes the lowercased Docusaurus `id` of its generated page
// (`config/bigwigadapter`). No heuristics.

export interface DocPage {
  // lowercased Docusaurus id / url slug, e.g. 'bigwigadapter'
  id: string
  // section under /jb2/docs/, '' for top-level pages
  section: string
  // full url path, e.g. 'config/bigwigadapter' or 'cli'
  urlPath: string
}

const SECTIONS = ['config', 'models', 'config_guides']

// generated reference pages live under these sections and key off the type name
const TYPE_SECTIONS = ['config', 'models']

// a type used in more than this fraction of example files is boilerplate
// (assembly/sequence/feature-track setup repeated everywhere) — linking it in
// every page is noise, so it's dropped from suggestions by default
const DEFAULT_COMMON_TYPE_RATIO = 0.5

const DOCS_BASE = 'https://jbrowse.org/jb2/docs/'

// section landing pages and stable hand-written top-level guides that have no
// own .md basename match but are always valid link targets
const KNOWN_INDEX_SLUGS = new Set(['config', 'models', 'config_guide'])

function readFirstId(file: string): string | undefined {
  const head = fs.readFileSync(file, 'utf8').slice(0, 600)
  const m = /^id:\s*(\S+)/m.exec(head)
  return m ? m[1] : undefined
}

function listMarkdown(dir: string): string[] {
  return fs.existsSync(dir)
    ? fs.readdirSync(dir).filter(f => f.endsWith('.md'))
    : []
}

// Build the set of valid generated doc pages from a checked-out `website/docs`
// tree. The url id is the page's `id:` frontmatter when present (autogenerated
// pages set it), else the lowercased filename (hand-written guides).
export function buildDocIndex(referenceDir: string): DocPage[] {
  const pages: DocPage[] = []
  for (const section of SECTIONS) {
    const dir = path.join(referenceDir, section)
    for (const file of listMarkdown(dir)) {
      const id =
        readFirstId(path.join(dir, file)) ??
        path.basename(file, '.md').toLowerCase()
      pages.push({ id, section, urlPath: `${section}/${id}` })
    }
  }
  for (const file of listMarkdown(referenceDir)) {
    const id =
      readFirstId(path.join(referenceDir, file)) ??
      path.basename(file, '.md').toLowerCase()
    pages.push({ id, section: '', urlPath: id })
  }
  return pages
}

function listFilesRecursive(dir: string, exts: string[]): string[] {
  const out: string[] = []
  const walk = (d: string) => {
    for (const entry of fs.readdirSync(d, { withFileTypes: true })) {
      const full = path.join(d, entry.name)
      if (entry.isDirectory()) {
        walk(full)
      } else if (exts.some(e => entry.name.endsWith(e))) {
        out.push(full)
      }
    }
  }
  if (fs.existsSync(dir)) {
    walk(dir)
  }
  return out
}

export interface BrokenLink {
  file: string
  url: string
  urlPath: string
}

// Scan content files for jbrowse.org doc links and return those whose target
// page is missing from the generated docs. Anchors and trailing slashes are
// ignored. Returns [] when everything resolves.
export function findBrokenDocLinks({
  contentDirs,
  referenceDir,
}: {
  contentDirs: string[]
  referenceDir: string
}): BrokenLink[] {
  const valid = new Set(buildDocIndex(referenceDir).map(p => p.urlPath))
  for (const slug of KNOWN_INDEX_SLUGS) {
    valid.add(slug)
  }
  const broken: BrokenLink[] = []
  const linkRe = /https:\/\/jbrowse\.org\/jb2\/docs\/([A-Za-z0-9_/]+)/g
  const files = contentDirs.flatMap(d =>
    listFilesRecursive(d, ['.md', '.astro']),
  )
  for (const file of files) {
    const text = fs.readFileSync(file, 'utf8')
    for (const m of text.matchAll(linkRe)) {
      const urlPath = m[1]!.replace(/\/$/, '')
      if (!valid.has(urlPath)) {
        broken.push({ file, url: m[0], urlPath })
      }
    }
  }
  return broken
}

export interface DocSuggestion {
  file: string
  // the config `type` value found, e.g. 'BigWigAdapter'
  term: string
  // matching generated pages (config and/or model), as full urls
  urls: string[]
}

// Scan example source for config `type: '...'` values and map each to the
// generated reference page(s) for that type. Output is advisory — a maintainer
// pastes the urls into the example's doc prose. Only types that actually have a
// generated page are returned (so plugin/test-only types are skipped). When
// `contentDirs` is given, types whose page url already appears anywhere in that
// prose are dropped, so the output is only the links still worth adding.
// Boilerplate types used across most examples (assembly/sequence setup) are
// dropped via `commonTypeRatio`.
export function suggestDocLinks({
  exampleDirs,
  referenceDir,
  contentDirs,
  commonTypeRatio = DEFAULT_COMMON_TYPE_RATIO,
}: {
  exampleDirs: string[]
  referenceDir: string
  contentDirs?: string[]
  commonTypeRatio?: number
}): DocSuggestion[] {
  const existing = contentDirs
    ? contentDirs
        .flatMap(d => listFilesRecursive(d, ['.md', '.astro']))
        .map(f => fs.readFileSync(f, 'utf8'))
        .join('\n')
    : ''
  const byIdSection = new Map<string, Set<string>>()
  for (const page of buildDocIndex(referenceDir)) {
    if (TYPE_SECTIONS.includes(page.section)) {
      const set = byIdSection.get(page.id) ?? new Set<string>()
      set.add(page.section)
      byIdSection.set(page.id, set)
    }
  }
  const typeRe = /type:\s*'([A-Z][A-Za-z0-9]+)'/g
  const files = exampleDirs.flatMap(d => listFilesRecursive(d, ['.tsx', '.ts']))

  // first pass: the distinct documented types per file, and how many files use
  // each (to identify boilerplate)
  const perFileTerms = new Map<string, string[]>()
  const fileCount = new Map<string, number>()
  for (const file of files) {
    const text = fs.readFileSync(file, 'utf8')
    const terms = [
      ...new Set(
        [...text.matchAll(typeRe)]
          .map(m => m[1]!)
          .filter(term => byIdSection.has(term.toLowerCase())),
      ),
    ]
    perFileTerms.set(file, terms)
    for (const term of terms) {
      fileCount.set(term, (fileCount.get(term) ?? 0) + 1)
    }
  }
  const commonThreshold = files.length * commonTypeRatio

  const suggestions: DocSuggestion[] = []
  for (const [file, terms] of perFileTerms) {
    for (const term of terms) {
      const id = term.toLowerCase()
      const urls = [...byIdSection.get(id)!]
        .sort()
        .map(s => `${DOCS_BASE}${s}/${id}/`)
      const allLinked = urls.every(u => existing.includes(u))
      const isCommon = (fileCount.get(term) ?? 0) > commonThreshold
      if (!isCommon && !(contentDirs && allLinked)) {
        suggestions.push({ file, term, urls })
      }
    }
  }
  return suggestions
}
